const item = $("Prepare Evaluation Item").first().json;

const grader_response = $input.first().json.output ?? $input.first().json.text ?? "";

const cleaned = grader_response
  .replace(/^```json\s*/i, "")
  .replace(/^```\s*/i, "")
  .replace(/\s*```$/i, "")
  .trim();

let formatted_response;

try {
  formatted_response = JSON.parse(cleaned);
} catch (error) {
  return [{
    json: {
      ...item,
      response: $('Answer Agent').first().json.output,
      strengths: [],
      weaknesses: [],
      reasoning: 'Grader returned invalid JSON — skipped.',
      score: null,
      error: true
    }
  }];
}

return [
  {
    json: {
      ...item,
      response : $('Answer Agent').first().json.output,
      ...formatted_response
    }
  }
];

const items = $input.all().map(item => ({
  category:   item.json.category,
  difficulty: item.json.difficulty,
  question:   item.json.question,
  response:   item.json.response,
  strengths:  item.json.strengths,
  weaknesses: item.json.weaknesses,
  reasoning:  item.json.reasoning,
  score:      item.json.score
}));

return [{
  json: {
    total_items:  items.length,
    results_json: JSON.stringify(items, null, 2)
  }
}];

const response = $input.first().json.output ?? $input.first().json.text ?? "";

const cleaned = response
  .replace(/^```json\s*/i, "")
  .replace(/^```\s*/i, "")
  .replace(/\s*```$/i, "")
  .trim();

let dataset;

try {
  dataset = JSON.parse(cleaned);
} catch (error) {
  throw new Error(`Invalid JSON returned by Dataset Generator.\n${error.message}`);
}

return dataset;
